    }
    fn nav_target(&self, _thy: &Thy, index: u64, _dir: NavDir, _mode: &str, lemma: &str) -> String {
        format!("/thy/trace/{index}/main/proof/{lemma}")
    }
    fn append_message(&self, _thy: &Thy) -> String {
